    ]},
    { char: "還", readings: [
      { zhuyin: "ㄏㄞˊ", word: "還是", sentence: "還有很多" },
      { zhuyin: "ㄏㄨㄢˊ", word: "歸還", sentence: "償還債務" },
    ]},
    { char: "種", readings: [
      { zhuyin: "ㄓㄨㄥˇ", word: "種類", sentence: "品種多樣" },
      { zhuyin: "ㄓㄨㄥˋ", word: "種植", sentence: "種花種草" },
    ]},
    { char: "教", readings: [
      { zhuyin: "ㄐㄧㄠ", word: "教書", sentence: "教導學生" },
      { zhuyin: "ㄐㄧㄠˋ", word: "教室", sentence: "宗教信仰" },
    ]},
    { char: "得", readings: [
      { zhuyin: "ㄉㄜˊ", word: "得到", sentence: "獲得獎勵" },
      { zhuyin: "ㄉㄟˇ", word: "得要", sentence: "非得如此" },
      { zhuyin: "˙ㄉㄜ", word: "跑得快", sentence: "做得很好" },
    ]},
    { char: "為", readings: [
      { zhuyin: "ㄨㄟˊ", word: "作為", sentence: "行為舉止" },
      { zhuyin: "ㄨㄟˋ", word: "因為", sentence: "為了目標" },
    ]},
    { char: "地", readings: [
      { zhuyin: "ㄉㄧˋ", word: "土地", sentence: "大地回春" },
      { zhuyin: "˙ㄉㄜ", word: "慢慢地", sentence: "輕輕地走" },
    ]},
    { char: "了", readings: [
      { zhuyin: "˙ㄌㄜ", word: "走了", sentence: "吃完了" },
      { zhuyin: "ㄌㄧㄠˇ", word: "了解", sentence: "明瞭清楚" },
    ]},
    { char: "乾", readings: [
      { zhuyin: "ㄍㄢ", word: "乾淨", sentence: "乾燥通風" },
      { zhuyin: "ㄑㄧㄢˊ", word: "乾坤", sentence: "扭轉乾坤" },
    ]},
    { char: "差", readings: [
      { zhuyin: "ㄔㄚ", word: "差別", sentence: "差異很大" },
      { zhuyin: "ㄔㄚˋ", word: "出差", sentence: "差遣任務" },
      { zhuyin: "ㄔㄚˇ", word: "差不多", sentence: "差點忘了" },
    ]},
    { char: "假", readings: [
      { zhuyin: "ㄐㄧㄚˇ", word: "真假", sentence: "假裝不知" },
      { zhuyin: "ㄐㄧㄚˋ", word: "放假", sentence: "暑假旅行" },
    ]},
  ];

  const startPolyphone = () => {
    // 打散所有 reading，每個 reading 是一道題
    const allItems = [];
    POLYPHONE_DATA.forEach(group => {
      group.readings.forEach(reading => {
        allItems.push({ char: group.char, allReadings: group.readings, ...reading });
      });
    });
    const shuffled = allItems.sort(() => Math.random() - 0.5).slice(0, 15);
    setPolyPool(shuffled);
    setPolyIdx(0);
    setPolyScore(0);
    setPolyTotal(0);
    setPolySelected(null);
    setPolyWrongs(new Set());
    setPolyResult(false);
    setPolyAnimKey(0);
    setPolyHistory([]);
    generatePolyQuestion(shuffled, 0);
    setScreen("polyphone");
  };

  const generatePolyQuestion = (pool, idx) => {
    if (idx >= pool.length) {
      setPolyResult(true);
      return;
    }
    const item = pool[idx];
    // 題目：顯示字 + 注音，選正確的造詞
    // 正確選項 = item.word
    // 錯誤選項 = 同字其他讀音的造詞 + 其他字的造詞
    const sameCharWrong = item.allReadings
      .filter(r => r.word !== item.word)
      .map(r => r.word);
    const otherCharWords = POLYPHONE_DATA
      .filter(g => g.char !== item.char)
      .flatMap(g => g.readings.map(r => r.word))
      .sort(() => Math.random() - 0.5);
    const wrongs = [...sameCharWrong, ...otherCharWords]
      .filter(w => w !== item.word)
      .slice(0, 3 - sameCharWrong.length > 0 ? 2 : 2);
    // 確保有 3 個選項（1 正確 + 2 錯誤）
    const finalWrongs = [...new Set([...sameCharWrong.slice(0, 1), ...wrongs])].slice(0, 2);
    const opts = [item.word, ...finalWrongs].sort(() => Math.random() - 0.5);
    setPolyQuestion({
      char: item.char,
      zhuyin: item.zhuyin,
      answer: item.word,
      sentence: item.sentence,
      allReadings: item.allReadings,
      options: opts,
    });
    setPolyAnimKey(k => k + 1);
  };

  const handlePolySelect = (opt) => {
    if (polySelected) return;
    if (polyWrongs.has(opt)) return;
    const isCorrect = opt === polyQuestion.answer;
    if (isCorrect) {
      setPolySelected(opt);
      setPolyScore(s => s + 1);
      setPolyTotal(t => t + 1);
      setPolyHistory(prev => [...prev, {
        char: polyQuestion.char,
        zhuyin: polyQuestion.zhuyin,
        word: polyQuestion.answer,
      }]);
      setTimeout(() => {
        const next = polyIdx + 1;
        setPolyIdx(next);
        setPolySelected(null);
        setPolyWrongs(new Set());
        generatePolyQuestion(polyPool, next);
      }, 1200);
    } else {
      setPolyWrongs(prev => new Set([...prev, opt]));
      if (polyWrongs.size === 0) {
        setPolyTotal(t => t + 1);
      }
    }
  };

  // ─── 下一題 ────────────────────────────────────────────────────
  const goNext = useCallback(() => {
    const elapsed = Date.now() - (questionStartTime || Date.now());
    setQuestionTimes(prev => [...prev, {
      char: quizPool[currentIdx]?.char,
      zhuyin: quizPool[currentIdx]?.zhuyin,
      time: elapsed,
      correct: firstAttemptCorrect,
    }]);

    const next = currentIdx + 1;
    if (next >= quizPool.length) {
      setShowResult(true);
      return;
    }
    setCurrentIdx(next);
    const q = generateQuestion(quizPool[next], quizPool, quizLevelRef.current);
    setQuestion(q);
    setSelected(null);
    setFirstAttemptCorrect(null);
    setWrongSelections(new Set());
    setAnimKey(k => k + 1);
    setQuestionStartTime(Date.now());
  }, [currentIdx, quizPool, questionStartTime, firstAttemptCorrect]);

  // ─── 選擇答案（嚴格模式）──────────────────────────────────────
  const handleSelect = (opt) => {
    if (!question) return;
    // 已經選對了就不能再點
    if (selected === question.answer) return;
    // 已經點過的錯誤選項不能再點
    if (wrongSelections.has(opt)) return;

    const isCorrect = opt === question.answer;

    if (isCorrect) {
      setSelected(opt);
      // 只有第一次就選對才計分
      if (firstAttemptCorrect === null) {
        setFirstAttemptCorrect(true);
        setScore(s => s + 1);
        setStreak(s => {
          const ns = s + 1;
          setBestStreak(b => Math.max(b, ns));
          return ns;
        });
      }
      setTotal(t => t + 1);
      // 自動跳下一題
      setTimeout(goNext, 800);
    } else {
      // 錯誤：標記此選項，不顯示正確答案
      if (firstAttemptCorrect === null) {
        setFirstAttemptCorrect(false);
        setStreak(0);
        setTotal(t => t + 1);
      }
      setWrongSelections(prev => new Set([...prev, opt]));
    }
  };

  // ─── 暫停/結束 ────────────────────────────────────────────────
  const togglePause = () => setIsPaused(p => !p);
  const endGame = (isEarly = false) => {
    clearInterval(timerRef.current);
    if (isEarly) {
      setEarlyEnd(true);
      setEarlyEndTime(formatTime(timeLeft));
    }
    // Record last question time
    if (quizPool[currentIdx] && questionStartTime) {
      const elapsed = Date.now() - questionStartTime;
      setQuestionTimes(prev => [...prev, {
        char: quizPool[currentIdx].char,
        zhuyin: quizPool[currentIdx].zhuyin,
        time: elapsed,
        correct: firstAttemptCorrect,
      }]);
    }
    setShowResult(true);
    setIsPaused(false);
  };

  // ─── 部首操作 ──────────────────────────────────────────────────
  const toggleRadical = (r) => {
    setSelectedRadicals(prev => {
      const next = new Set(prev);
      if (next.has(r)) next.delete(r); else next.add(r);
      return next;
    });
  };
  const selectAllRadicals = () => setSelectedRadicals(new Set(ALL_RADICALS));
  const clearAllRadicals = () => setSelectedRadicals(new Set());

  // ─── 弱點分析：思考時間最久前 5 字 ─────────────────────────────
  const weaknesses = [...questionTimes]
    .sort((a, b) => b.time - a.time)
    .slice(0, 5);

  // ─── 當前題目的多音字提示 ──────────────────────────────────────
